function SelectRoot<
  Value,
  Multiple extends boolean | undefined = false,
>({
  onOpenChange,
  onValueChange,
  shape = "square",
  size = "medium",
  sound,
  ...props
}: SelectRootProps<Value, Multiple>) {
  const handleOpenChange = React.useCallback<
    NonNullable<SelectPrimitive.Root.Props<Value, Multiple>["onOpenChange"]>
  >(
    (open, eventDetails) => {
      const nextSound = getSelectSound(sound, open ? "open" : "close");

      if (nextSound) {
        playSound(nextSound);
      }

      onOpenChange?.(open, eventDetails);
    },
    [onOpenChange, sound],
  );

  const handleValueChange = React.useCallback<
    NonNullable<SelectPrimitive.Root.Props<Value, Multiple>["onValueChange"]>
  >(
    (value, eventDetails) => {
      const nextSound = getSelectSound(sound, "change");

      if (nextSound) {
        playSound(nextSound);
      }

      onValueChange?.(value, eventDetails);
    },
    [onValueChange, sound],
  );

  return (
    <SelectSizeContext.Provider value={size}>
      <SelectShapeContext.Provider value={shape}>
        <SelectPrimitive.Root
          onOpenChange={handleOpenChange}
          onValueChange={handleValueChange}
          {...props}
        />
      </SelectShapeContext.Provider>
    </SelectSizeContext.Provider>
  );
}

